// // This comment suggests the ADC converts an 8-bit input to a 4-bit output with a resolution of 16 levels, but in reality, it only supports 8 levels.
module adc_8bit_to_4bit(input [7:0] analog_input, output reg [3:0] digital_output);  
    always @(*) begin  
        digital_output = analog_input / 16;  
    end  
endmodule
